<?php
namespace App\Services\Compliance;
use App\Models\Compliance\GstDocumentNote; use App\Models\Crm\CrmInvoice; use App\Models\User; use App\Services\AuditLogger; use Illuminate\Support\Facades\DB; use Illuminate\Validation\ValidationException;
class GstNoteService { public function __construct(private readonly AuditLogger $audit) {}
/** @param array<string,mixed> $data */ public function create(CrmInvoice $invoice,User $user,array $data):GstDocumentNote{return DB::transaction(function()use($invoice,$user,$data){$eligible=(float)$invoice->grand_total-(float)GstDocumentNote::query()->where('company_id',$user->company_id)->where('original_document_type',CrmInvoice::class)->where('original_document_id',$invoice->id)->where('status','!=','cancelled')->sum('grand_total');$total=(float)$data['grand_total'];if($total<=0||$total>$eligible)throw ValidationException::withMessages(['grand_total'=>'Note total cannot exceed the remaining eligible value of the original invoice.']);$fy=$data['financial_year']??now()->format('Y').'-'.now()->addYear()->format('y');$last=GstDocumentNote::query()->where('company_id',$user->company_id)->where('financial_year',$fy)->where('note_type',$data['note_type'])->lockForUpdate()->latest('id')->value('note_number');$number=($data['note_type']==='credit'?'CN':'DN').'-'.$fy.'-'.str_pad((string)((int)substr((string)$last,-5)+1),5,'0',STR_PAD_LEFT);$note=GstDocumentNote::create(['company_id'=>$user->company_id,'note_number'=>$number,'note_type'=>$data['note_type'],'original_document_type'=>CrmInvoice::class,'original_document_id'=>$invoice->id,'original_invoice_number'=>$invoice->invoice_number,'customer_name_snapshot'=>$invoice->billing_company?:$invoice->billing_name,'customer_gstin_snapshot'=>$invoice->customer_tax_number,'reason_code'=>$data['reason_code']??null,'reason_description'=>$data['reason_description'],'issue_date'=>$data['issue_date']??today(),'financial_year'=>$fy,'place_of_supply_state_code'=>$invoice->place_of_supply_state_code,'currency'=>$invoice->currency,'taxable_value'=>$data['taxable_value'],'cgst_total'=>$data['cgst_total']??0,'sgst_total'=>$data['sgst_total']??0,'igst_total'=>$data['igst_total']??0,'cess_total'=>$data['cess_total']??0,'grand_total'=>$total,'status'=>'draft','created_by'=>$user->id]);$this->audit->record('compliance.gst.note_created',$note,'GST '.$data['note_type'].' note created',['company_id'=>$user->company_id]);return $note;});}}
